class SearchTest : public ::testing::TestWithParam<std::string> {
  protected:
    void SetUp() override {}
};

TEST_P(SearchTest, RecallMatchesGroundTruth) {
    std::string index_type = GetParam();
    size_t d = D;
    auto data = TestUtils::LoadTestData(d);
    auto gt = TestUtils::ComputeBruteForceKNN(
        data.train.data(),
        data.queries.data(),
        TestUtils::N_TRAIN,
        TestUtils::N_QUERIES,
        d,
        TestUtils::KNN
    );

    auto index = TestUtils::BuildIndex(index_type, data.train.data(), TestUtils::N_TRAIN, d);
    ASSERT_NE(index, nullptr);
    index->SetNProbe(16);

    float recall = TestUtils::ComputeAverageRecall(
        *index, data.queries.data(), TestUtils::N_QUERIES, d, TestUtils::KNN, gt
    );

    auto key = std::make_tuple(index_type, d, size_t{16});
    auto it = RECALL_GROUND_TRUTH.find(key);
    if (it != RECALL_GROUND_TRUTH.end()) {
        float expected = it->second;
        EXPECT_NEAR(recall, expected, RECALL_TOLERANCE)
            << "Recall regression: got " << recall << ", expected ~" << expected;
    }
}

TEST_P(SearchTest, RecallMonotonicallyIncreasesWithNProbe) {
    std::string index_type = GetParam();
    size_t d = D;
    auto data = TestUtils::LoadTestData(d);
    auto gt = TestUtils::ComputeBruteForceKNN(
        data.train.data(),
        data.queries.data(),
        TestUtils::N_TRAIN,
        TestUtils::N_QUERIES,
        d,
        TestUtils::KNN
    );

    auto index = TestUtils::BuildIndex(index_type, data.train.data(), TestUtils::N_TRAIN, d);
    ASSERT_NE(index, nullptr);

    uint32_t num_clusters = index->GetNumClusters();
    std::vector<size_t> nprobes = {1, 2, 4, 8, 16, 32, 64};
    nprobes.push_back(num_clusters);
    nprobes.erase(
        std::remove_if(
            nprobes.begin(), nprobes.end(), [num_clusters](size_t p) { return p > num_clusters; }
        ),
        nprobes.end()
    );
    std::sort(nprobes.begin(), nprobes.end());
    nprobes.erase(std::unique(nprobes.begin(), nprobes.end()), nprobes.end());

    float prev_recall = 0.0f;
    for (size_t nprobe : nprobes) {
        index->SetNProbe(nprobe);
        float recall = TestUtils::ComputeAverageRecall(
            *index, data.queries.data(), TestUtils::N_QUERIES, d, TestUtils::KNN, gt
        );

        EXPECT_GE(recall, prev_recall - 0.01f) << "Recall decreased from " << prev_recall << " to "
                                               << recall << " when increasing nprobe to " << nprobe;
        prev_recall = recall;
    }
}

TEST_P(SearchTest, ResultsAreSortedByDistance) {
    std::string index_type = GetParam();
    size_t d = D;
    auto data = TestUtils::LoadTestData(d);
    auto index = TestUtils::BuildIndex(index_type, data.train.data(), TestUtils::N_TRAIN, d);
    index->SetNProbe(16);

    for (size_t q = 0; q < std::min<size_t>(50, TestUtils::N_QUERIES); ++q) {
        auto results = index->Search(data.queries.data() + q * d, TestUtils::KNN);
        for (size_t i = 1; i < results.size(); ++i) {
            EXPECT_LE(results[i - 1].distance, results[i].distance + 1e-6f)
                << "Results not sorted for query " << q << " at position " << i;
        }
    }
}

